namespace AMH.BuyMenu.ItemsImage
{
    public class Item
    {
        public string Name { get; set; }
        public string RuName { get; set; }
        public string Category { get; set; }
        public int Level { get; set; }
        public string Enchantment { get; set; }
        public string Quality { get; set; }
        public string ImagePath { get; set; }

        public Item(string name, string ruName, string category, int level, string imagePath)
        {
            Name = name;
            RuName = ruName;
            Category = category;
            Level = level;
            ImagePath = imagePath;
            Enchantment = "None";
            Quality = "Normal";
        }

        public string GetNameByCulture(CultureInfo ci)
        {
            if (ci.Name == "ru-RU" || ci.TwoLetterISOLanguageName == "ru")
            {
                return string.IsNullOrEmpty(RuName) ? Name : RuName;
            }
            else
            {
                return Name;
            }
        }
        public static class Items
        {

            public static void PopulateListView(ListView listView)
            {
                listView.Items.Clear(); // Очищаем listView перед заполнением.
                CultureInfo currentCulture = Thread.CurrentThread.CurrentCulture;
                foreach (var item in ItemsList)
                {
                    ListViewItem lvi = new ListViewItem(); // Создание нового ListViewItem
                    lvi.ImageKey = item.ImagePath;         // Установка ключа изображения
                    lvi.SubItems.Add(item.GetNameByCulture(currentCulture)); // Название (учитывая текущую культуру)
                    lvi.SubItems.Add("1");                                  // Количество
                    lvi.SubItems.Add(item.Category);                        // Категория
                    lvi.SubItems.Add(item.Level.ToString());                // Уровень
                    lvi.SubItems.Add(item.Enchantment);                     // Зачарование
                    lvi.SubItems.Add(item.Quality);                         // Качество
                    listView.Items.Add(lvi);                                // Добавление элемента в listView
                }
            }

            public static void PopulateListView2(ListView listView, ImageList imageList)
            {
                CultureInfo currentCulture = Thread.CurrentThread.CurrentCulture;
                listView.Items.Clear(); // Очищаем listView перед заполнением.
                foreach (var item in ItemsList)
                {
                    ListViewItem lvi = new ListViewItem(); // Создание нового ListViewItem
                    lvi.ImageKey = item.ImagePath;         // Установка ключа изображения
                    lvi.SubItems.Add(item.GetNameByCulture(currentCulture)); // Название (учитывая текущую культуру)
                    lvi.SubItems.Add(item.Category);                        // Категория
                    lvi.SubItems.Add(item.Level.ToString());                // Уровень
                    listView.Items.Add(lvi);                                // Добавление элемента в listView
                }
                listView.SmallImageList = imageList; // Присваивание списка изображений к listView
            }
            public static List<Item> ItemsList { get; } = new List<Item>();
            static Items()
            {
                Items.ItemsList.Add(new Item("Adept’s Arcane Staff", "Посох Адепта", "Staff", 4, "T4_MAIN_ARCANESTAFF"));
                Items.ItemsList.Add(new Item("Journeyman’s Arcane Staff", "Посох Подмастерья", "Staff", 3, "T3_MAIN_ARCANESTAFF"));
            }
        }
    }
}

